 1	import { Drawer, DrawerContent } from '@patternfly/react-core';
 2	import { fireEvent, render, waitFor } from '@testing-library/react';
 3	import * as React from 'react';
 4	
 5	import { DefaultColumnSample } from '../../../__tests-data__/columns';
 6	import { FilterDefinitionSample, FiltersSample } from '../../../__tests-data__/filters';
 7	import { FlowsSample, UnknownFlow } from '../../../__tests-data__/flows';
 8	import RecordPanel, { RecordDrawerProps } from '../record-panel';
 9	
10	describe('<RecordPanel />', () => {
11	  const mocks: RecordDrawerProps = {
12	    record: FlowsSample[0],
13	    columns: DefaultColumnSample,
14	    filters: FiltersSample,
15	    filterDefinitions: FilterDefinitionSample,
16	    range: 300,
17	    type: 'flowLog',
18	    canSwitchTypes: false,
19	    allowPktDrops: false,
20	    setFilters: jest.fn(),
21	    setRange: jest.fn(),
22	    setType: jest.fn(),
23	    onClose: jest.fn(),
24	    id: 'record-panel-test'
25	  };
26	
27	  const renderInDrawer = (props: RecordDrawerProps) =>
28	    render(
29	      <Drawer isExpanded>
30	        <DrawerContent panelContent={<RecordPanel {...props} />}>
31	          <div />
32	        </DrawerContent>
33	      </Drawer>
34	    );
35	
36	  it('should render component', async () => {
37	    const { rerender } = renderInDrawer(mocks);
38	    await waitFor(() => {
39	      expect(document.querySelector('#record-panel-test')).toBeTruthy();
40	    });
41	    const fieldContainers = document.querySelectorAll('.record-field-container');
42	    expect(fieldContainers.length).toBe(20);
43	    expect(document.querySelector('[data-test-id="drawer-field-IcmpType"]')).toBeNull();
44	    expect(document.querySelector('[data-test-id="drawer-field-IcmpCode"]')).toBeNull();
45	
46	    rerender(
47	      <Drawer isExpanded>
48	        <DrawerContent panelContent={<RecordPanel {...mocks} record={UnknownFlow} />}>
49	          <div />
50	        </DrawerContent>
51	      </Drawer>
52	    );
53	    await waitFor(() => {
54	      expect(document.querySelectorAll('.record-field-container').length).toBe(4);
55	    });
56	  });
57	
58	  it('should close on click', async () => {
59	    renderInDrawer(mocks);
60	    await waitFor(() => {
61	      expect(document.querySelector('[data-test-id="drawer-close-button"]')).toBeTruthy();
62	    });
63	    fireEvent.click(document.querySelector('[data-test-id="drawer-close-button"]')!);
64	    expect(mocks.onClose).toHaveBeenCalled();
65	  });
66	
67	  it('should render ICMP', async () => {
68	    const flowWithICMP = {
69	      ...mocks.record,
70	      fields: {
71	        ...mocks.record.fields,
72	        IcmpType: 8,
73	        IcmpCode: 0
74	      }
75	    };
76	    renderInDrawer({ ...mocks, record: flowWithICMP });
77	    await waitFor(() => {
78	      expect(document.querySelector('[data-test-id="drawer-field-IcmpType"]')).toBeTruthy();
79	    });
80	    expect(document.querySelector('[data-test-id="drawer-field-IcmpCode"]')).toBeTruthy();
81	  });
82	});

